import type { QuestionV2 } from "../../../types";
export const CH10_PRACTICAL_GEOMETRY: QuestionV2[] = [
  // t1 — Constructing Triangles SSS, SAS, ASA, RHS (40 q)
  { id:"bo-mth-7-ch10-001", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"remember", marks:1, estimatedTimeMinutes:2, question:"What tools are needed to construct triangles?", answer:"Ruler (straight edge), compass (for arcs), protractor (for angles), pencil. Sometimes a set square is also used.", steps:[{stepNumber:1,title:"Tools",explanation:"Ruler, compass, protractor, pencil."}], hint:"Compass draws arcs of specific radius.", keyConcepts:["construction tools"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-002", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"remember", marks:2, estimatedTimeMinutes:3, question:"State the condition for a triangle to be constructible given three sides.", answer:"A triangle can be constructed if and only if the sum of any two sides is greater than the third side (triangle inequality). E.g., sides 3cm, 4cm, 5cm satisfy: 3+4>5, 3+5>4, 4+5>3 ✓.", steps:[{stepNumber:1,title:"Triangle inequality",explanation:"a+b>c for all combinations of sides a,b,c."}], hint:"The longest side must be less than the sum of the other two.", keyConcepts:["triangle inequality","triangle constructibility"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-003", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"understand", marks:2, estimatedTimeMinutes:3, question:"Outline the steps to construct a triangle given SSS (sides a, b, c).", answer:"1. Draw base BC=a. 2. With B as centre, draw arc of radius c. 3. With C as centre, draw arc of radius b. 4. Mark intersection as A. 5. Join AB and AC. △ABC is the required triangle.", steps:[{stepNumber:1,title:"SSS construction steps",explanation:"Draw base, draw two arcs from each end, intersection is third vertex."}], hint:"The two arcs intersect at the third vertex A.", keyConcepts:["SSS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-004", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"understand", marks:2, estimatedTimeMinutes:3, question:"Outline the steps to construct a triangle given SAS.", answer:"1. Draw base BC. 2. At B, construct angle of given measure. 3. Cut off BA = given length on that angle. 4. Join AC. △ABC is complete.", steps:[{stepNumber:1,title:"SAS steps",explanation:"Draw base, construct angle at one end, mark side length, join."}], hint:"The given angle is at the vertex between the two given sides.", keyConcepts:["SAS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-005", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"understand", marks:2, estimatedTimeMinutes:3, question:"How do you construct a right-angled triangle (RHS) given the hypotenuse and one side?", answer:"1. Draw base BC (one leg). 2. At B, construct a 90° angle using a compass and ruler. 3. Draw a ray from B at 90°. 4. With C as centre, draw arc of radius = hypotenuse, intersecting the ray at A. 5. Join AC.", steps:[{stepNumber:1,title:"RHS steps",explanation:"Draw one leg, make 90° at one end, arc from other end with hypotenuse length."}], hint:"The hypotenuse arc from one end intersects the perpendicular from the other end.", keyConcepts:["RHS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-006", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Can a triangle be constructed with sides 5cm, 6cm, and 11cm? Why?", answer:"No. 5+6=11, which is NOT greater than 11. The triangle inequality requires the sum of any two sides to be STRICTLY greater than the third. 5+6=11 ✗ (degenerate/collapsed line).", steps:[{stepNumber:1,title:"Test triangle inequality",explanation:"5+6=11 (not >11) → cannot form a triangle.",result:"Cannot be constructed"}], hint:"Sum of two sides must be strictly greater than third.", keyConcepts:["triangle inequality"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-007", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Check if a triangle can be formed with sides: (a) 3,4,5 (b) 2,7,9 (c) 6,6,6.", answer:"(a) 3+4=7>5 ✓; 3+5>4 ✓; 4+5>3 ✓ → YES. (b) 2+7=9 (not >9) → NO. (c) 6+6=12>6 ✓ → YES (equilateral).", steps:[{stepNumber:1,title:"Apply inequality",explanation:"(a)YES, (b)NO (2+7=9), (c)YES.",result:"YES, NO, YES"}], hint:"Check: sum of two smallest > largest.", keyConcepts:["triangle inequality"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-008", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct a triangle with sides 4cm, 5cm, and 6cm. Describe each step.", answer:"1. Draw BC=6cm. 2. With B as centre, radius 4cm — draw arc. 3. With C as centre, radius 5cm — draw arc. 4. Arcs meet at A. 5. Join AB and AC. Verify: BC=6, AB=4, AC=5.", steps:[{stepNumber:1,title:"SSS",explanation:"Base BC=6. Arc from B (r=4), arc from C (r=5). A=intersection. Join AB, AC."}], hint:"Always start with the base (longest side is convenient).", keyConcepts:["SSS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-009", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Describe the steps to construct △ABC with AB=5cm, ∠B=60°, BC=4cm (SAS).", answer:"1. Draw BC=4cm. 2. At B, construct 60° using compass. 3. Along the 60° ray from B, mark A at 5cm. 4. Join AC. △ABC has AB=5, ∠B=60°, BC=4.", steps:[{stepNumber:1,title:"SAS",explanation:"Base BC=4. Angle 60° at B. BA=5 along ray. Join AC."}], hint:"Construct 60° using equilateral triangle arc method.", keyConcepts:["SAS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-010", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Describe construction of △PQR with ∠Q=90°, QR=5cm, PR (hypotenuse)=7cm (RHS).", answer:"1. Draw QR=5cm. 2. At Q, construct 90° using compass. 3. With R as centre, draw arc of radius 7cm, cutting the perpendicular at P. 4. Join PR. ∠Q=90°, QR=5, PR=7.", steps:[{stepNumber:1,title:"RHS",explanation:"Base QR=5. 90° at Q. Arc from R (r=7) meets perpendicular at P."}], hint:"The perpendicular at Q and the hypotenuse arc from R meet at P.", keyConcepts:["RHS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-011", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct △ABC with ∠A=60°, ∠B=70°, AB=6cm (ASA). Describe key steps.", answer:"1. Draw AB=6cm. 2. At A, construct 60°; at B, construct 70°. 3. The two rays from A and B intersect at C. △ABC has ∠A=60°, ∠B=70°, AB=6cm (included side).", steps:[{stepNumber:1,title:"ASA",explanation:"Base AB=6. Angle 60° at A, 70° at B. Rays meet at C."}], hint:"Note ∠C=50° (angle sum 180°). The third vertex is where the two angle rays meet.", keyConcepts:["ASA construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-012", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"How would you construct an isosceles triangle with equal sides 5cm each and base 6cm?", answer:"1. Draw base BC=6cm. 2. With B as centre, arc r=5cm. 3. With C as centre, arc r=5cm. 4. Arcs meet at A. 5. Join AB and AC. Both AB and AC are 5cm.", steps:[{stepNumber:1,title:"SSS (two sides equal)",explanation:"Base 6. Equal arcs 5cm from both ends. A=intersection.",result:"Isosceles triangle constructed"}], hint:"Both arcs have the same radius (equal sides) of 5cm.", keyConcepts:["isosceles triangle construction","SSS"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-013", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Describe construction of an equilateral triangle with side 5cm.", answer:"1. Draw BC=5cm. 2. With B as centre, arc r=5cm. 3. With C as centre, arc r=5cm. 4. Arcs intersect at A (two arcs of equal radius will intersect at exactly 60° from each end). 5. Join AB and AC. △ABC is equilateral.", steps:[{stepNumber:1,title:"All sides equal",explanation:"Three arcs of 5cm each. Intersection gives equilateral triangle.",result:"Equilateral triangle constructed"}], hint:"All three radii are the same → equilateral.", keyConcepts:["equilateral triangle construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-014", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Perimeter of △PQR is 14cm. PQ=4cm, QR=5cm. Construct the triangle.", answer:"PR=14−4−5=5cm. 1. Draw QR=5cm. 2. With Q as centre, arc r=4cm. 3. With R as centre, arc r=5cm. 4. Arcs meet at P. 5. Join PQ and PR.", steps:[{stepNumber:1,title:"Find third side",explanation:"PR=14−9=5cm."},{stepNumber:2,title:"SSS construction",explanation:"Base=5, arcs 4 and 5cm.",result:"Triangle constructed"}], hint:"Find the third side from perimeter first.", keyConcepts:["SSS from perimeter"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-015", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"icse", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct △ABC where AB=6cm, ∠B=45°, ∠C=60°. Find ∠A first.", answer:"∠A=180−45−60=75°. Construction (ASA): 1. Draw AB=6cm. 2. At A, construct 75°; at B, construct 45°. 3. Rays from A and B meet at C.", steps:[{stepNumber:1,title:"Find ∠A",explanation:"180−45−60=75°."},{stepNumber:2,title:"ASA",explanation:"AB=6cm; angle 75° at A, 45° at B.",result:"△ABC constructed"}], hint:"Find the third angle first (angle sum = 180°).", keyConcepts:["ASA construction","angle sum"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-016", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"icse", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:5, estimatedTimeMinutes:9, question:"Can you construct a unique triangle given ASA? What about AAS? Compare.", answer:"ASA (two angles + included side): unique triangle. Given ∠A, AB, ∠B — rays from A and B at those angles meet at unique C. AAS (two angles + non-included side): also unique because the third angle is determined (180°−A−B=C), converting it to ASA effectively. Both give unique triangles.", steps:[{stepNumber:1,title:"ASA uniqueness",explanation:"Two angle rays from endpoints of the given side meet at exactly one point."},{stepNumber:2,title:"AAS uniqueness",explanation:"Third angle = 180°−given angles. Then becomes effectively ASA.",result:"Both ASA and AAS give unique triangles"}], hint:"Uniqueness: can only one triangle be drawn from the given information?", keyConcepts:["uniqueness of construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-017", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"A plot of land is triangular with sides 50m, 70m, and 90m. Can such a plot exist?", answer:"50+70=120>90 ✓; 50+90=140>70 ✓; 70+90=160>50 ✓. Yes, such a triangular plot can exist (triangle inequality is satisfied).", steps:[{stepNumber:1,title:"Check inequality",explanation:"All three conditions satisfied → valid triangle.",result:"YES, can exist"}], hint:"All three triangle inequality conditions must hold.", keyConcepts:["triangle inequality real world"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-018", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"A triangular support uses two rods of 8cm and 6cm. The angle between them is 90°. Find the third rod length.", answer:"Third side (hypotenuse) = √(8²+6²) = √(64+36) = √100 = 10cm. This is an SAS construction with the included angle of 90°.", steps:[{stepNumber:1,title:"Pythagoras",explanation:"√(64+36)=10cm.",result:"Third rod = 10cm"}], hint:"SAS with 90° angle → use Pythagoras for the third side.", keyConcepts:["SAS","Pythagoras"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-019", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"In a construction, you know ∠A=50°, AB=7cm, AC=6cm (SAS). Describe the construction.", answer:"1. Draw AB=7cm. 2. At A, construct 50°. 3. Along the 50° ray from A, mark C at 6cm. 4. Join BC. △ABC has ∠A=50°, AB=7cm, AC=6cm.", steps:[{stepNumber:1,title:"SAS construction",explanation:"Base AB=7. Angle 50° at A. AC=6 along ray. Join BC."}], hint:"The 50° angle is at A, between sides AB and AC.", keyConcepts:["SAS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-020", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t1", topicName:"Constructing Triangles", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"analyse", marks:4, estimatedTimeMinutes:7, question:"Why does SSS give a unique triangle (one construction), but AAA gives infinitely many?", answer:"SSS: three side lengths fix all angles (via law of cosines) and the shape uniquely — only one triangle (up to congruence) fits. AAA: angles sum to 180° and are consistent, but the side lengths are not fixed — infinitely many triangles of different sizes share the same three angles (all similar to each other). Triangle size is not determined by angles alone.", steps:[{stepNumber:1,title:"SSS",explanation:"Sides determine angles → unique triangle."},{stepNumber:2,title:"AAA",explanation:"Angles don't fix size → infinite triangles (similar, not congruent).",result:"SSS unique; AAA infinite"}], hint:"Think: scale factor can be anything if only angles are given.", keyConcepts:["uniqueness of construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  // t2 — Constructing Special Lines in Triangles (20 q + extended from t1)
  { id:"bo-mth-7-ch10-021", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"remember", marks:1, estimatedTimeMinutes:2, question:"How do you bisect a line segment using compass and ruler?", answer:"1. Draw segment AB. 2. With A as centre, arc r > AB/2. 3. With B as centre, same arc. 4. The two arcs intersect at P and Q. 5. Line PQ is the perpendicular bisector of AB, bisecting it at midpoint M.", steps:[{stepNumber:1,title:"Steps",explanation:"Equal arcs from A and B; their intersection gives perpendicular bisector."}], hint:"The two arcs must have equal radius greater than half AB.", keyConcepts:["perpendicular bisector construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-022", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"remember", marks:1, estimatedTimeMinutes:2, question:"How do you bisect an angle using compass and ruler?", answer:"1. Draw angle AOB. 2. With O as centre, draw arc cutting OA at P and OB at Q. 3. With P and Q as centres, draw equal arcs intersecting at R. 4. OR is the angle bisector of ∠AOB.", steps:[{stepNumber:1,title:"Angle bisector",explanation:"Arc from O cuts arms; equal arcs from those points; join O to intersection."}], hint:"The intersection of the two arcs from P and Q lies on the angle bisector.", keyConcepts:["angle bisector construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-023", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"understand", marks:2, estimatedTimeMinutes:3, question:"How do you construct 60° using compass and ruler (without protractor)?", answer:"1. Draw a ray from O. 2. With O as centre, draw a large arc crossing the ray at P. 3. With P as centre (same radius), draw an arc crossing the first arc at Q. 4. ∠POQ = 60°. (This uses the equilateral triangle property.)", steps:[{stepNumber:1,title:"60° construction",explanation:"Base arc from O; equal arc from where it cuts the ray; intersection gives 60°."}], hint:"An equilateral triangle always has 60° angles.", keyConcepts:["60° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-024", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"concept", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"understand", marks:2, estimatedTimeMinutes:3, question:"How can you construct a 90° angle without a protractor?", answer:"Method 1: Bisect 180° (a straight angle): construct the perpendicular bisector of a line segment — this gives 90°. Method 2: Use 60° (already constructible), then bisect the remaining 120° to get 30°, then 60+30=90°. Or: draw a semicircle and use Thales' theorem.", steps:[{stepNumber:1,title:"90° construction",explanation:"Perpendicular bisector of a segment gives 90°. OR bisect 180° using two arcs."}], hint:"Perpendicular bisector meets the segment at 90°.", keyConcepts:["90° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-025", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct 30° using compass and ruler. Describe the steps.", answer:"1. Construct 60° (using equilateral arc method). 2. Bisect the 60° angle using compass. 3. Half of 60° = 30°.", steps:[{stepNumber:1,title:"30° = half of 60°",explanation:"Construct 60°, then bisect it.",result:"30° obtained"}], hint:"30° = 60°/2.", keyConcepts:["30° construction","angle bisection"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-026", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"How do you construct 120° using compass and ruler?", answer:"Construct 60° (equilateral arc from a point). Then 120° = 60° + 60° = two successive 60° arcs from the same base point. OR: 120° = 180°−60° (supplement of 60°).", steps:[{stepNumber:1,title:"120° = 2 × 60°",explanation:"Draw two successive 60° arcs: first gives Q at 60°, another from Q gives R at 120°.",result:"120° constructed"}], hint:"Add two 60° arcs on the same side.", keyConcepts:["120° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-027", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct 75° using compass and ruler only.", answer:"75° = 60° + 15° = 60° + (30°/2). Steps: 1. Construct 90° at O. 2. Construct 60° at O. 3. Bisect the angle between 60° and 90° (which is 30°) → 15°. 4. 60° + 15° = 75°. Or: 75° = 90° − 15° = bisect the region from 60° to 90°.", steps:[{stepNumber:1,title:"Method",explanation:"Construct 90° and 60°. Bisect the 30° gap between them to get 15°. 60°+15°=75°.",result:"75° constructed"}], hint:"75° = 60° + half of (90°−60°) = 60° + 15°.", keyConcepts:["75° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-028", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct a line parallel to a given line through a point P not on the line.", answer:"1. Draw a transversal from P to the given line, meeting it at Q. 2. Construct an angle at P equal to ∠PQ(line) using compass (copy the angle). 3. The ray at this equal angle from P is parallel to the given line (corresponding angles are equal).", steps:[{stepNumber:1,title:"Parallel line construction",explanation:"Transversal PQ; copy corresponding angle at P; resulting ray is parallel."}], hint:"Equal corresponding angles → parallel lines.", keyConcepts:["parallel line construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-029", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct the perpendicular from a point P to a line AB (where P is not on the line).", answer:"1. With P as centre, draw an arc cutting line AB at X and Y. 2. With X and Y as centres, draw equal arcs on the same side as P (or opposite). They intersect at Q. 3. Join PQ — this is perpendicular to AB.", steps:[{stepNumber:1,title:"Perpendicular from external point",explanation:"Arc from P cuts AB at X,Y; equal arcs from X,Y meet at Q; PQ⊥AB."}], hint:"The perpendicular from P is the shortest distance from P to line AB.", keyConcepts:["perpendicular from external point"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-030", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct an equilateral triangle with side 5cm. Then draw the perpendicular bisector of each side. Do all three bisectors meet at one point?", answer:"Construction: equilateral triangle ABC side 5cm. Perpendicular bisectors of BC, CA, AB each constructed. Yes, all three perpendicular bisectors meet at the circumcenter of the triangle, which is equidistant from all three vertices. This is the circumscribed circle's center.", steps:[{stepNumber:1,title:"Construct triangle",explanation:"Equilateral, side 5cm."},{stepNumber:2,title:"Three perpendicular bisectors",explanation:"Each meets the midpoint of a side at 90°."},{stepNumber:3,title:"Concurrence",explanation:"All three meet at circumcenter.",result:"Yes, they meet at the circumcenter"}], hint:"Perpendicular bisectors of a triangle's sides are concurrent at the circumcenter.", keyConcepts:["circumcenter","perpendicular bisectors concurrent"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-031", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"icse", questionFormat:"LongAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:5, estimatedTimeMinutes:10, question:"Construct 45° using compass and ruler. Describe every step.", answer:"1. Draw a ray OA. 2. Construct 90° at O (perpendicular): draw arc from O, then arc from where it cuts the ray, and arc from the second intersection to get 90°. Mark the 90° angle as ∠AOP = 90°. 3. Bisect ∠AOP: draw an arc from O cutting OA at Q and OP at R. With Q and R as centres, equal arcs intersect at S. 4. Join OS — this bisects 90° into two 45° angles.", steps:[{stepNumber:1,title:"Construct 90°",explanation:"Perpendicular at O gives 90°."},{stepNumber:2,title:"Bisect 90°",explanation:"Bisect the right angle → 45°.",result:"45° constructed"}], hint:"45° = 90°/2.", keyConcepts:["45° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-032", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"A carpenter wants to divide a plank of wood in half. Which geometric construction does this represent?", answer:"Bisecting a line segment (constructing the perpendicular bisector). The perpendicular bisector crosses the plank at its midpoint, dividing it into two equal halves.", steps:[{stepNumber:1,title:"Real world",explanation:"Dividing in half = perpendicular bisector = midpoint construction."}], hint:"Midpoint divides a segment into two equal parts.", keyConcepts:["perpendicular bisector real world"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-033", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"A surveyor marks a right angle at a corner of a plot. Which construction is used?", answer:"Construction of a 90° angle using a compass (perpendicular bisector method or the 60°+30° combination). In surveying, the 3-4-5 right triangle (Pythagorean triple) is also commonly used to create a right angle.", steps:[{stepNumber:1,title:"90° angle",explanation:"Perpendicular bisector construction. In practice, 3-4-5 triangle."},{stepNumber:2,title:"Application",explanation:"Ensures corners of the plot are exactly 90°.",result:"Right angle construction applied"}], hint:"Perpendicular lines meet at 90°.", keyConcepts:["90° construction real world"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-034", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:4, estimatedTimeMinutes:7, question:"Why can all angles that are multiples of 3° be constructed with compass and ruler, but 40° cannot?", answer:"Constructible angles are those that can be built from 60° (equilateral triangle) and 90° using bisection. 60° bisected → 30° → 15° → 7.5°... etc. 90° bisected → 45° → 22.5°... Multiples of 3° that can be expressed as combinations of these are constructible. However, 40° = 180°/4.5 — it would require trisecting 120°, which is a famous impossible construction (trisection of an angle is impossible with compass and ruler). 40° cannot be expressed as a finite combination of bisections from 60° or 90°.", steps:[{stepNumber:1,title:"Constructible angles",explanation:"Built from 60° and 90° via bisection."},{stepNumber:2,title:"40° requires trisection",explanation:"40°=120°/3 — trisection is impossible with compass/ruler.",result:"40° is not constructible with compass and ruler"}], hint:"Trisecting an arbitrary angle is one of the three classical impossible constructions.", keyConcepts:["constructible angles","impossibility"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-035", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"create", marks:5, estimatedTimeMinutes:9, question:"Design a step-by-step construction for a triangle with angles 30°, 60°, 90° and hypotenuse 10cm (given hypotenuse, two angles).", answer:"1. Find the right angle: ∠C=90°, ∠A=30°, ∠B=60°. 2. Draw AB (hypotenuse)=10cm. 3. At A, construct 30°. 4. At B, construct 60°. 5. The rays from A (at 30°) and B (at 60°) intersect at C. 6. Verify ∠C=90° (should be since 30+60+90=180). Alternative: since the triangle is a 30-60-90, BC=5cm, AC=5√3cm. Draw BC=5, construct 90° at C, mark A at 5√3.", steps:[{stepNumber:1,title:"Angles",explanation:"∠A=30°, ∠B=60°, ∠C=90°."},{stepNumber:2,title:"ASA with hypotenuse",explanation:"AB=10cm; angle 30° at A, 60° at B; rays meet at C.",result:"30-60-90 triangle constructed"}], hint:"For 30-60-90: sides are in ratio 1:√3:2.", keyConcepts:["30-60-90 triangle","construction from angles and hypotenuse"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-036", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"analyse", marks:4, estimatedTimeMinutes:7, question:"A unique triangle requires minimum conditions. What is the minimum information needed?", answer:"Minimum conditions for unique triangle: (a) SSS: all 3 sides, or (b) SAS: 2 sides + included angle, or (c) ASA/AAS: 2 angles + 1 side, or (d) RHS (for right triangle): hypotenuse + 1 side. In all cases, 3 independent pieces of information determine a unique triangle. Fewer conditions (e.g., 2 sides only, or 3 angles) give infinitely many possibilities.", steps:[{stepNumber:1,title:"Minimum: 3 independent conditions",explanation:"SSS, SAS, ASA, AAS, RHS each use exactly 3 pieces of information."},{stepNumber:2,title:"Fewer is insufficient",explanation:"2 sides: many triangles. 3 angles: similar family (infinite sizes).",result:"3 independent conditions needed"}], hint:"Triangle has 6 parts (3 sides, 3 angles); need 3 in the right combination.", keyConcepts:["minimum construction conditions","uniqueness"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-037", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Can a triangle be formed with angles 90°, 100°, and 30°?", answer:"No. The sum = 90+100+30 = 220° ≠ 180°. The angle sum of a triangle must be exactly 180°.", steps:[{stepNumber:1,title:"Check angle sum",explanation:"90+100+30=220°≠180° → invalid triangle.",result:"Cannot be formed"}], hint:"Interior angles of any triangle sum to 180°.", keyConcepts:["angle sum of triangle"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-038", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Name the type of triangle and the construction criterion for: ∠B=90°, BC=6cm, AB=8cm.", answer:"Right-angled triangle. Criterion: SAS (sides AB=8, BC=6, included angle ∠B=90°). Or equivalently, RHS if we compute hypotenuse AC=√(64+36)=10cm and use (∠B=90°, AC=10, BC=6).", steps:[{stepNumber:1,title:"Type",explanation:"Right-angled (∠B=90°)."},{stepNumber:2,title:"Criterion",explanation:"SAS: AB=8, ∠B=90°, BC=6.",result:"Right triangle; SAS (or RHS)"}], hint:"90° angle means right-angled triangle.", keyConcepts:["right triangle construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-039", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct △ABC given: ∠B=30°, AB+AC=9cm, BC=7cm. Describe the main steps.", answer:"This is a non-standard construction: 1. Draw BC=7cm. 2. At B, draw ray at 30°. 3. On the ray from B, mark a point D such that BD=AB+AC=9cm. 4. Join DC. 5. Draw the perpendicular bisector of DC. It meets the ray BD at A. 6. A is the required vertex (since AD=AC by perpendicular bisector property).", steps:[{stepNumber:1,title:"Main idea",explanation:"Mark BD=AB+AC=9 on the angle ray. Perpendicular bisector of DC cuts the ray at A where AD=AC, giving AB=BD−AD=BD−AC=9−AC, so AB+AC=9 ✓.",result:"Construction valid"}], hint:"The perpendicular bisector trick: any point on it is equidistant from D and C.", keyConcepts:["non-standard triangle construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-040", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"How do you copy an angle equal to ∠ABC to another point O?", answer:"1. With B as centre, draw arc cutting BA at P and BC at Q. 2. Draw a ray from O. 3. With O as centre, same radius, draw arc cutting the ray at P'. 4. With P' as centre, radius=PQ, draw arc. 5. It intersects the first arc at Q'. 6. ∠P'OQ' = ∠ABC.", steps:[{stepNumber:1,title:"Copy angle",explanation:"Arc from B (BP=BQ), then same arc from O, then chord PQ replicated."}], hint:"Copy the chord length PQ to recreate the same angle at O.", keyConcepts:["copying an angle"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-041", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct 150° using compass and ruler.", answer:"150° = 180° − 30°. Steps: 1. Draw a straight angle (180°) — a straight line. 2. Construct 30° on one side: first construct 60°, then bisect to get 30°. 3. The remaining angle from the 30° to the straight line = 150°.", steps:[{stepNumber:1,title:"150° = 180°−30°",explanation:"Draw straight angle; subtract 30° to get 150°.",result:"150° constructed"}], hint:"150° is the supplement of 30°.", keyConcepts:["150° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-042", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Describe how to construct a triangle given: two sides and a non-included angle (SSA). Is the result always unique?", answer:"SSA: Draw base BC. At B, draw the given angle. Mark side BA at given length. From A, draw arc of the second given side length, cutting BC (or its extension) at C. This may give 0, 1, or 2 solutions — SSA is not unique (ambiguous case). Hence SSA is NOT a valid congruence criterion.", steps:[{stepNumber:1,title:"SSA ambiguity",explanation:"The arc from A may intersect BC at 0, 1, or 2 points → not always unique.",result:"NOT always unique; SSA is ambiguous"}], hint:"This is called the 'ambiguous case' — up to two triangles may be possible.", keyConcepts:["SSA ambiguous case"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-043", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Draw a line segment PQ=7cm and bisect it. What is the length of each half?", answer:"Each half = 7/2 = 3.5cm. Perpendicular bisector passes through the midpoint M, giving PM=MQ=3.5cm.", steps:[{stepNumber:1,title:"Bisect",explanation:"PM=MQ=3.5cm.",result:"Each half = 3.5cm"}], hint:"Perpendicular bisector divides the segment into two equal halves.", keyConcepts:["line bisection"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-044", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct angle 22.5° using compass and ruler.", answer:"22.5° = 45°/2. Steps: 1. Construct 90°. 2. Bisect 90° → 45°. 3. Bisect 45° → 22.5°.", steps:[{stepNumber:1,title:"22.5° = 45°/2",explanation:"90°→45°→22.5° by successive bisection.",result:"22.5° constructed"}], hint:"Keep halving: 90→45→22.5.", keyConcepts:["22.5° construction","bisection"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-045", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:5, estimatedTimeMinutes:9, question:"Using only a ruler and compass, can you construct a regular hexagon? Describe the method.", answer:"Yes. A regular hexagon has all sides equal and all angles 120°. Method: 1. Draw a circle with radius r. 2. Starting at any point on the circle, mark off arcs of length r around the circle. 3. A circle's radius fits exactly 6 times around the circumference (since each step subtends 60° at the center). 4. Connecting the 6 points gives a regular hexagon with side length = r.", steps:[{stepNumber:1,title:"Circle and arcs",explanation:"Radius r; mark off 6 equal arcs around the circle."},{stepNumber:2,title:"Connect points",explanation:"6 points → regular hexagon with side r.",result:"Regular hexagon constructed"}], hint:"The key insight: circle radius = chord length for 60° arc (equilateral triangle property).", keyConcepts:["regular hexagon construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-046", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"analyse", marks:4, estimatedTimeMinutes:7, question:"Explain why two arcs of equal radius from the endpoints of a segment always intersect at a point equidistant from both endpoints.", answer:"Let segment AB have endpoints A and B. Arc from A (radius r) = set of all points at distance r from A. Arc from B (radius r) = set of all points at distance r from B. Their intersection P satisfies PA=r and PB=r. Therefore PA=PB, so P is equidistant from A and B — it lies on the perpendicular bisector of AB.", steps:[{stepNumber:1,title:"PA=r and PB=r",explanation:"Each arc has radius r → PA=PB=r."},{stepNumber:2,title:"Equidistant → perpendicular bisector",explanation:"PA=PB → P on perpendicular bisector of AB.",result:"P is always equidistant from A and B"}], hint:"Think about what 'arc of radius r' means geometrically.", keyConcepts:["perpendicular bisector property"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-047", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"create", marks:5, estimatedTimeMinutes:8, question:"Design a method to construct a square with a given diagonal.", answer:"1. Draw diagonal d (given length). 2. Construct the perpendicular bisector of d — it meets d at center O. 3. On the perpendicular bisector, mark two points at distance d/2 from O (one on each side). 4. These four points (two ends of d, two on perpendicular bisector) are the vertices of the square. 5. Connect adjacent vertices.", steps:[{stepNumber:1,title:"Perpendicular bisector of diagonal",explanation:"Diagonals of a square bisect each other at right angles."},{stepNumber:2,title:"Equal half-diagonals",explanation:"All four vertices are d/2 from center O.",result:"Square constructed from diagonal"}], hint:"Square's diagonals are equal and perpendicular bisectors of each other.", keyConcepts:["square from diagonal","perpendicular bisector"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-048", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:4, estimatedTimeMinutes:7, question:"In a construction, why is it important that the compass setting (radius) is not accidentally changed mid-construction?", answer:"If the radius changes mid-construction, the arcs drawn will not have the intended equal length, causing the geometric properties being constructed to fail. For example, when bisecting a segment, if the radius from A differs from the radius from B, the intersection point will NOT lie on the perpendicular bisector. Precision of compass setting is essential for geometric accuracy.", steps:[{stepNumber:1,title:"Why radius must be constant",explanation:"Changing radius mid-construction invalidates the equal-length condition all constructions rely on.",result:"Consistent radius ensures geometric accuracy"}], hint:"All construction proofs assume equal radii wherever stated.", keyConcepts:["construction accuracy"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-049", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"analyse", marks:4, estimatedTimeMinutes:7, question:"An architect needs to construct a triangular window with angles 30°, 60°, 90° and the longest side = 120cm. What are the other two sides?", answer:"In a 30-60-90 triangle: sides are in ratio 1:√3:2. Hypotenuse (longest) = 120cm (opposite 90°). Side opposite 30° = 120/2 = 60cm. Side opposite 60° = 60√3 ≈ 103.9cm.", steps:[{stepNumber:1,title:"30-60-90 ratio",explanation:"1:√3:2. Hyp=2 parts=120 → unit=60."},{stepNumber:2,title:"Sides",explanation:"60cm and 60√3≈103.9cm.",result:"60cm and 103.9cm"}], hint:"In 30-60-90: hyp=2×(shortest side).", keyConcepts:["30-60-90 triangle sides"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-050", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"create", marks:5, estimatedTimeMinutes:9, question:"Construct a triangle with sides proportional to 3:4:5, and perimeter = 36cm.", answer:"Total parts = 3+4+5=12. Scale: 36/12=3. Sides: 9cm, 12cm, 15cm. Verify triangle inequality: 9+12=21>15 ✓; right triangle (9²+12²=81+144=225=15²). Construction: SSS with sides 9,12,15cm.", steps:[{stepNumber:1,title:"Scale",explanation:"36÷12=3. Sides: 9,12,15cm."},{stepNumber:2,title:"Verify",explanation:"9+12>15 ✓; also a right triangle."},{stepNumber:3,title:"Construct",explanation:"SSS: base 15, arcs 9 and 12.",result:"Sides 9, 12, 15 cm (right triangle)"}], hint:"Scale factor = perimeter/sum of ratio parts.", keyConcepts:["scaling triangles","SSS construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-051", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"A kite ABCD has AB=AD=5cm and CB=CD=7cm. Describe the construction.", answer:"1. Draw diagonal AC (axis of symmetry). 2. Mark A at top. 3. With A as centre, arcs r=5 cm on both sides for B and D. 4. With C at bottom (determined), arcs r=7 cm from B and D should meet at C. Alternative: draw AB=5cm, with A arc r=5 for D, with B arc r=7 and D arc r=7 to find C.", steps:[{stepNumber:1,title:"Kite construction",explanation:"Draw axis, mark two equal arcs from A for B and D; arcs from B and D for C.",result:"Kite ABCD constructed"}], hint:"Kite: two pairs of adjacent equal sides.", keyConcepts:["kite construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-052", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:4, estimatedTimeMinutes:7, question:"A student constructed a triangle by drawing three arbitrary line segments and connecting them. The result was not a triangle (lines didn't close). What went wrong?", answer:"The student violated the triangle inequality: the sum of two segments was not greater than the third. For a valid triangle, you must verify a+b>c for all combinations. If one side is too long (≥ sum of other two), the arcs from the endpoints of the long side will not intersect, so the triangle cannot be closed.", steps:[{stepNumber:1,title:"Triangle inequality violated",explanation:"If longest side ≥ sum of others, arcs don't meet → not a triangle.",result:"Triangle inequality must be checked first"}], hint:"Always verify triangle inequality before attempting construction.", keyConcepts:["triangle inequality error"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-053", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Sides of a triangle are 5cm, 12cm, 13cm. Is it a right triangle? Verify using Pythagoras.", answer:"5²+12²=25+144=169=13²=169 ✓. Yes, it is a right-angled triangle with hypotenuse 13cm.", steps:[{stepNumber:1,title:"Pythagoras check",explanation:"5²+12²=169=13² → right triangle.",result:"Yes, right triangle"}], hint:"Pythagoras: a²+b²=c² for right triangle.", keyConcepts:["Pythagoras","right triangle verification"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-054", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Without a protractor, construct 135° using compass.", answer:"135° = 90° + 45° = 180° − 45°. Method: 1. Draw a straight line (180°). 2. Construct 45° from one end. 3. The remaining angle (from 45° to 180°) = 135°.", steps:[{stepNumber:1,title:"135° = 180°−45°",explanation:"Construct 45° (bisect 90°); supplement of 45° = 135°.",result:"135° constructed"}], hint:"135° = supplement of 45°.", keyConcepts:["135° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-055", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"What is the condition for constructing a triangle given two sides and the angle between them? State the criterion.", answer:"Given two sides and the INCLUDED angle (SAS), a unique triangle can always be constructed. The included angle must be the angle between the two given sides.", steps:[{stepNumber:1,title:"SAS condition",explanation:"Two sides + included angle → unique triangle. Always constructible (any two lengths with any angle between them form a valid triangle).",result:"SAS always gives unique triangle"}], hint:"'Included' angle = angle between the two sides.", keyConcepts:["SAS construction condition"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-056", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct △ABC with AB=5cm, ∠A=90°, AC=4cm. Find BC.", answer:"∠A=90°, so BC is the hypotenuse. BC=√(AB²+AC²)=√(25+16)=√41≈6.4cm. Construction: draw AB=5, at A construct 90°, mark AC=4 along the perpendicular, join BC.", steps:[{stepNumber:1,title:"Pythagoras",explanation:"BC=√41≈6.4cm."},{stepNumber:2,title:"Construction",explanation:"SAS: AB=5, ∠A=90°, AC=4.",result:"BC≈6.4cm"}], hint:"Right angle at A means BC is the hypotenuse.", keyConcepts:["SAS construction","Pythagoras"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-057", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct the circumcircle of equilateral triangle with side 4cm. Describe steps.", answer:"1. Construct equilateral triangle ABC side 4cm. 2. Draw perpendicular bisectors of two sides (AB and BC). 3. Their intersection O is the circumcenter. 4. With O as centre and OA as radius, draw circle. This circle passes through all three vertices.", steps:[{stepNumber:1,title:"Triangle",explanation:"Equilateral, side 4cm."},{stepNumber:2,title:"Circumcenter",explanation:"Intersection of perpendicular bisectors of two sides."},{stepNumber:3,title:"Circumcircle",explanation:"Circle with center O, radius OA.",result:"Circumcircle constructed"}], hint:"Circumcenter = intersection of perpendicular bisectors of sides.", keyConcepts:["circumcircle","circumcenter"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-058", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"How do you construct the median from vertex A to side BC in △ABC?", answer:"1. Construct △ABC. 2. Find midpoint M of BC: draw perpendicular bisector of BC — it meets BC at M. 3. Join AM. AM is the median from A to BC.", steps:[{stepNumber:1,title:"Midpoint of BC",explanation:"Perpendicular bisector of BC meets it at M."},{stepNumber:2,title:"Median",explanation:"Join A to M = median.",result:"Median AM constructed"}], hint:"Median goes from vertex to midpoint of opposite side.", keyConcepts:["median construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-059", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct the altitude from vertex A to BC in △ABC where AB=5cm, BC=7cm, AC=6cm.", answer:"1. Construct △ABC with SSS. 2. With A as centre, draw arc cutting BC (or extended) at two points P and Q. 3. With P and Q as centres, equal arcs intersect at H below BC. 4. Join AH — this is perpendicular to BC. The foot of perpendicular D is where AH meets BC.", steps:[{stepNumber:1,title:"SSS construction",explanation:"Draw triangle first."},{stepNumber:2,title:"Perpendicular from A",explanation:"Arc from A cuts BC at P,Q; equal arcs from P,Q meet at H; AH⊥BC.",result:"Altitude constructed"}], hint:"Altitude = perpendicular from a vertex to the opposite side.", keyConcepts:["altitude construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-060", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"How many distinct triangles can be constructed with sides 5cm, 5cm, and 5cm?", answer:"Exactly one (up to congruence). All equilateral triangles with the same side length are congruent to each other — SSS gives a unique triangle.", steps:[{stepNumber:1,title:"SSS uniqueness",explanation:"SSS → unique triangle. All equilateral 5cm triangles are congruent.",result:"Exactly one (up to congruence)"}], hint:"SSS always gives exactly one triangle.", keyConcepts:["SSS uniqueness"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-061", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"analyse", marks:3, estimatedTimeMinutes:5, question:"Estimate the smallest angle of a triangle with sides 3cm, 5cm, and 7cm.", answer:"Smallest angle is opposite the smallest side (3cm). Using cosine rule: cos A = (b²+c²−a²)/(2bc) = (25+49−9)/(2×5×7) = 65/70 = 0.929. A = cos⁻¹(0.929) ≈ 21.8°.", steps:[{stepNumber:1,title:"Cosine rule",explanation:"cos A = (25+49−9)/(70) = 65/70."},{stepNumber:2,title:"Angle",explanation:"A ≈ 21.8°.",result:"Smallest angle ≈ 21.8°"}], hint:"Smallest angle is opposite the shortest side.", keyConcepts:["cosine rule","smallest angle"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-062", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:4, estimatedTimeMinutes:7, question:"Prove: The perpendicular bisector of a chord of a circle passes through the centre.", answer:"Let AB be a chord of circle with centre O. Perpendicular bisector of AB passes through M (midpoint of AB) at 90°. OA=OB (radii). O is equidistant from A and B → O lies on the perpendicular bisector of AB (locus of points equidistant from A and B is the perp bisector). Hence the perpendicular bisector of chord AB passes through O.", steps:[{stepNumber:1,title:"OA=OB (radii)",explanation:"O equidistant from A and B."},{stepNumber:2,title:"Locus",explanation:"Equidistant from A and B → on perpendicular bisector.",result:"Perp bisector of chord passes through centre O"}], hint:"The center is equidistant from all points on the circle, including chord endpoints.", keyConcepts:["chord perpendicular bisector","circle theorem"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-063", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"create", marks:5, estimatedTimeMinutes:8, question:"Design a method to construct a triangle given its three altitudes h_a, h_b, h_c.", answer:"Given three altitudes h_a, h_b, h_c, find the sides using area: Area = (1/2)×a×h_a = (1/2)×b×h_b = (1/2)×c×h_c. Let area = K. Then a = 2K/h_a, b = 2K/h_b, c = 2K/h_c. But K is unknown. Use: 1/h_a + 1/h_b + 1/h_c must be consistent with Heron's formula. Numerical approach: assume K=1, compute a=2/h_a, b=2/h_b, c=2/h_c, scale to satisfy Heron's formula. Then construct using SSS.", steps:[{stepNumber:1,title:"Relate altitudes to sides",explanation:"a=2K/h_a, etc. Sides are proportional to 1/h_a : 1/h_b : 1/h_c."},{stepNumber:2,title:"Scale and construct",explanation:"Sides in ratio 1/h_a : 1/h_b : 1/h_c, scaled to match area; then SSS.",result:"Construction method designed"}], hint:"Area = (1/2)×base×altitude; altitudes are inversely proportional to corresponding sides.", keyConcepts:["altitude-side relationship","construction from altitudes"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-064", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"hots", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"evaluate", marks:4, estimatedTimeMinutes:7, question:"A student claims: 'I can construct any angle using compass and ruler.' Agree or disagree? Give a specific example.", answer:"Disagree. Not all angles are constructible with compass and ruler. Constructible angles are those that are multiples of 3° (expressible via 60° and its bisections). Famous examples of non-constructible angles: 1° (requires trisection of 3°), 20° (requires trisection of 60°). In general, an angle θ is constructible if and only if it can be expressed using the four arithmetic operations and square roots applied to rational numbers.", steps:[{stepNumber:1,title:"Not all angles constructible",explanation:"Angles requiring trisection (e.g., 20°, 1°) are impossible."},{stepNumber:2,title:"Example",explanation:"20°: requires trisecting 60°; classical impossibility.",result:"Disagree; 20° is an example of a non-constructible angle"}], hint:"Trisection of a general angle is one of the three classical impossibilities.", keyConcepts:["constructibility limits"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-065", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct 105° using compass and ruler.", answer:"105° = 60° + 45° = 60° + (90°/2). Steps: 1. Construct 60°. 2. Construct 90° from the same base point. 3. Bisect the 30° gap between 60° and 90° to get 15°. 4. 60° + 45° = 60° + 90°/2. Actually: 105° = 60° + 45°. Construct 60°, then from the 60° ray construct another 45° → total 105°.", steps:[{stepNumber:1,title:"105° = 60° + 45°",explanation:"Construct 60°, then add 45° (= bisected 90°).",result:"105° constructed"}], hint:"105° = 60° + 45° OR 90° + 15°.", keyConcepts:["105° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-066", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct a quadrilateral ABCD where AB=5cm, BC=4cm, CD=3cm, DA=4cm, ∠A=60°.", answer:"1. Draw AB=5cm. 2. At A, construct 60°, mark AD=4cm along this ray. 3. With D as centre, arc r=3cm; with B as centre, arc r=4cm; intersection is C. 4. Join BC and DC to complete ABCD.", steps:[{stepNumber:1,title:"Steps",explanation:"AB=5, ∠A=60°, AD=4; arcs from D(r=3) and B(r=4) find C.",result:"Quadrilateral ABCD constructed"}], hint:"Construct two adjacent sides and angle first, then use arcs to find C.", keyConcepts:["quadrilateral construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-067", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Sides are 4, 5, 9. Can a triangle be formed?", answer:"No. 4+5=9 (NOT strictly greater than 9). Triangle inequality requires sum of any two sides > third side.", steps:[{stepNumber:1,title:"Check",explanation:"4+5=9 (not >9) → invalid.",result:"Cannot be formed"}], hint:"Need sum of two sides STRICTLY greater than third.", keyConcepts:["triangle inequality"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-068", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct △ABC: ∠B=90°, ∠C=45°, BC=6cm. Find AB and AC.", answer:"∠A=45°. Since ∠B=90° and ∠C=∠A=45°, it's an isosceles right triangle. AB=BC=6cm. AC (hypotenuse)=6√2≈8.49cm.", steps:[{stepNumber:1,title:"Angles",explanation:"∠A=180−90−45=45°."},{stepNumber:2,title:"Isosceles",explanation:"∠A=∠C=45° → AB=BC=6. AC=6√2.",result:"AB=6cm, AC=6√2cm"}], hint:"Two equal angles → isosceles; AB=BC.", keyConcepts:["45-45-90 triangle"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
  { id:"bo-mth-7-ch10-069", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"analyse", marks:4, estimatedTimeMinutes:7, question:"A satellite dish is parabolic. An engineer approximates its cross-section with an isosceles triangle of base 4m and equal sides 5m. Verify constructability and find the height.", answer:"Triangle inequality: 5+5=10>4 ✓; 5+4=9>5 ✓. Valid triangle. Height h (altitude from apex): Using Pythagoras: h=√(5²−2²)=√(25−4)=√21≈4.58m.", steps:[{stepNumber:1,title:"Triangle inequality",explanation:"Valid (✓)."},{stepNumber:2,title:"Height",explanation:"h=√(25−4)=√21≈4.58m.",result:"Valid; h≈4.58m"}], hint:"Height of isosceles triangle: h=√(side²−(base/2)²).", keyConcepts:["isosceles triangle height","construction validity"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-070", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"competency", questionFormat:"ShortAnswer", difficulty:"Easy", bloomsLevel:"apply", marks:2, estimatedTimeMinutes:3, question:"Name the geometric construction used when you draw a semicircle and mark its diameter ends as A and B, then mark any point C on the semicircle and connect A, C, B. What angle is ∠ACB?", answer:"∠ACB=90° (Thales' theorem / angle in a semicircle). Any angle inscribed in a semicircle (where the diameter is the hypotenuse) is a right angle.", steps:[{stepNumber:1,title:"Thales theorem",explanation:"Angle in semicircle = 90°.",result:"∠ACB=90°"}], hint:"Thales' theorem: angle in a semicircle is always 90°.", keyConcepts:["Thales theorem","angle in semicircle"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"original" },
  { id:"bo-mth-7-ch10-071", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct △ABC with ∠A=45°, ∠B=90°, and AB=4cm. Find AC.", answer:"∠C=180−45−90=45°. Right triangle at B, isosceles: AB=BC=4cm. AC (hypotenuse)=4√2≈5.66cm. Construction: draw AB=4, at B erect 90°, at A construct 45°; rays meet at C.", steps:[{stepNumber:1,title:"Find sides",explanation:"∠C=45°; AB=BC=4; AC=4√2≈5.66cm."},{stepNumber:2,title:"Construct",explanation:"ASA with AB=4, ∠A=45°, ∠B=90°.",result:"AC=4√2≈5.66cm"}], hint:"45-45-90 triangle: legs equal, hypotenuse = leg×√2.", keyConcepts:["45-45-90 triangle construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-072", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Draw a line segment AB=8cm. Construct its perpendicular bisector and verify the midpoint.", answer:"1. Draw AB=8cm. 2. With A as centre, arc r>4cm (e.g., 5cm). 3. Same arc from B. 4. Arcs intersect at P and Q above and below AB. 5. Join PQ — this is the perpendicular bisector. 6. It meets AB at M. Verify: AM=MB=4cm.", steps:[{stepNumber:1,title:"Construct",explanation:"Two arcs from A and B; their intersection gives PQ⊥AB."},{stepNumber:2,title:"Verify",explanation:"AM=MB=4cm.",result:"Midpoint M, AM=MB=4cm"}], hint:"Perpendicular bisector divides segment into two 4cm halves.", keyConcepts:["perpendicular bisector verification"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-073", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct the incircle of △ABC with AB=5cm, BC=6cm, CA=7cm.", answer:"1. Construct △ABC with SSS. 2. Bisect all three angles using compass. 3. The three angle bisectors meet at the incenter I. 4. Drop a perpendicular from I to any side — the foot is at distance r (inradius). 5. Draw circle with center I, radius r (= perpendicular distance to side). This circle is the incircle.", steps:[{stepNumber:1,title:"SSS triangle",explanation:"Construct triangle."},{stepNumber:2,title:"Incenter",explanation:"Intersection of angle bisectors."},{stepNumber:3,title:"Incircle",explanation:"Circle centered at I, radius = distance from I to any side.",result:"Incircle constructed"}], hint:"Incenter = intersection of angle bisectors; incircle touches all three sides.", keyConcepts:["incircle","incenter construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-074", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"ncert", questionFormat:"ShortAnswer", difficulty:"Medium", bloomsLevel:"apply", marks:3, estimatedTimeMinutes:5, question:"Construct an angle of 15° using compass and ruler.", answer:"15° = 30°/2. Steps: 1. Construct 60°. 2. Bisect 60° → 30°. 3. Bisect 30° → 15°.", steps:[{stepNumber:1,title:"15° derivation",explanation:"60°→30°→15° by successive bisections.",result:"15° constructed"}], hint:"15° = 60°/4.", keyConcepts:["15° construction"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"ncert" },
  { id:"bo-mth-7-ch10-075", schemaVersion:2, classNum:7, subject:"Mathematics", board:"Both", chapterId:"ch10", chapterName:"Practical Geometry", topicId:"t2", topicName:"Special Constructions and Lines", questionType:"previous-year", questionFormat:"ShortAnswer", difficulty:"Hard", bloomsLevel:"apply", marks:4, estimatedTimeMinutes:7, question:"Construct a line through P perpendicular to a given line l, where P is ON the line l.", answer:"1. On line l, mark P. 2. With P as centre, draw arc cutting l at A and B (on both sides). 3. With A and B as centres, equal arcs (larger radius) intersect at Q. 4. Join PQ — PQ⊥l at P.", steps:[{stepNumber:1,title:"Perpendicular at a point ON the line",explanation:"Arc from P cuts l at A and B; equal arcs from A and B meet at Q; PQ⊥l.",result:"Perpendicular constructed at P"}], hint:"This is perpendicular at a point ON the line (unlike perpendicular FROM an external point).", keyConcepts:["perpendicular at a point on line"], conceptsCovered:[], prerequisites:[], commonErrors:[], tags:[], source:"previous-year" },
];
